import{_ as n,o as i,c as t,S as e}from"./chunks/framework.C6RQlTYc.js";const c=JSON.parse('{"title":"预训练与微调","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_11-pretraining_finetuning.md","filePath":"直击概念/17ai/s_ai_11-pretraining_finetuning.md","lastUpdated":1778207238000}'),r={name:"直击概念/17ai/s_ai_11-pretraining_finetuning.md"};function o(l,a,s,u,h,g){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="预训练与微调" tabindex="-1">预训练与微调 <a class="header-anchor" href="#预训练与微调" aria-label="Permalink to &quot;预训练与微调&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><h3 id="预训练-pre-training" tabindex="-1">预训练（Pre-training） <a class="header-anchor" href="#预训练-pre-training" aria-label="Permalink to &quot;预训练（Pre-training）&quot;">​</a></h3><p>在<strong>海量无标注数据</strong>上，用大规模算力训练一个通用基础模型，让模型学会语言的通用表示（语法、常识、推理等）。这是 LLM 最核心、最昂贵的阶段。</p><ul><li><strong>数据</strong>：万亿级别的 token（网页、书籍、代码、论文等）</li><li><strong>任务</strong>：自监督学习（如 预测下一个 token / 填空）</li><li><strong>成本</strong>：数千万美元级别（算力+电力）</li></ul><h3 id="微调-fine-tuning" tabindex="-1">微调（Fine-tuning） <a class="header-anchor" href="#微调-fine-tuning" aria-label="Permalink to &quot;微调（Fine-tuning）&quot;">​</a></h3><p>在预训练模型的基础上，用<strong>特定领域的小规模标注数据</strong>进一步调整模型参数，使其适应特定任务或风格。</p><ul><li><strong>数据</strong>：数千到数百万条标注样本</li><li><strong>目的</strong>：适配垂直领域（医疗/法律）、调整输出风格、增强特定能力</li></ul><h2 id="微调的三种方式" tabindex="-1">微调的三种方式 <a class="header-anchor" href="#微调的三种方式" aria-label="Permalink to &quot;微调的三种方式&quot;">​</a></h2><h3 id="全量微调-full-fine-tuning" tabindex="-1">全量微调（Full Fine-tuning） <a class="header-anchor" href="#全量微调-full-fine-tuning" aria-label="Permalink to &quot;全量微调（Full Fine-tuning）&quot;">​</a></h3><p>更新模型的<strong>所有参数</strong>。</p><ul><li>效果最好但计算成本高</li><li>需要存储整个新模型</li><li>适用于有充足资源的场景</li></ul><h3 id="参数高效微调-peft" tabindex="-1">参数高效微调（PEFT） <a class="header-anchor" href="#参数高效微调-peft" aria-label="Permalink to &quot;参数高效微调（PEFT）&quot;">​</a></h3><p>只更新模型的<strong>一小部分参数</strong>，大幅降低微调成本。</p><h4 id="lora-low-rank-adaptation" tabindex="-1">LoRA（Low-Rank Adaptation） <a class="header-anchor" href="#lora-low-rank-adaptation" aria-label="Permalink to &quot;LoRA（Low-Rank Adaptation）&quot;">​</a></h4><p>在原始权重旁添加低秩矩阵，只训练这些新增的小矩阵：</p><ul><li>训练参数量可降至原模型的 0.1%~1%</li><li>微调后只需保存 LoRA 权重文件（几 MB 到几百 MB）</li><li>可在同一基座模型上切换多个 LoRA（多任务能力）</li></ul><h4 id="qlora" tabindex="-1">QLoRA <a class="header-anchor" href="#qlora" aria-label="Permalink to &quot;QLoRA&quot;">​</a></h4><p>LoRA + 4-bit 量化，进一步降低显存需求（可在消费级 GPU 上微调 70B 模型）。</p><h3 id="指令微调-instruction-tuning" tabindex="-1">指令微调（Instruction Tuning） <a class="header-anchor" href="#指令微调-instruction-tuning" aria-label="Permalink to &quot;指令微调（Instruction Tuning）&quot;">​</a></h3><p>用<strong>指令-回答</strong>格式的数据训练，让模型学会遵循人类指令，而不是简单地续写文本。</p><p>ChatGPT 的成功很大程度归功于指令微调。</p><h2 id="对齐训练-alignment" tabindex="-1">对齐训练（Alignment） <a class="header-anchor" href="#对齐训练-alignment" aria-label="Permalink to &quot;对齐训练（Alignment）&quot;">​</a></h2><p>在微调之后，需要让模型的输出与<strong>人类价值观</strong>对齐：</p><ul><li><strong>SFT（Supervised Fine-Tuning）</strong>：用高质量人工标注数据训练</li><li><strong>RLHF（Reinforcement Learning from Human Feedback）</strong>：训练奖励模型→用强化学习优化</li><li><strong>DPO（Direct Preference Optimization）</strong>：直接优化偏好数据，无需奖励模型</li></ul><p>详见 RLHF 章节。</p><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>预训练和微调的核心区别是什么？</li><li>什么是 LoRA？为什么它在前端/中小企业中很实用？</li><li>一个完整的 LLM 训练流程包含哪些阶段？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2106.09685" target="_blank" rel="noreferrer">LoRA: Low-Rank Adaptation of Large Language Models</a></li><li><a href="https://arxiv.org/abs/2305.14314" target="_blank" rel="noreferrer">QLoRA: Efficient Finetuning of Quantized LLMs</a></li></ul>',30)])])}const p=n(r,[["render",o]]);export{c as __pageData,p as default};
